<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>New Company</title><style>:root{--line:#e5e7eb;--bg:rgba(15,23,42,.55);--panel:#fff;--text:#111827;--muted:#6b7280;--green:#389B5B}*{box-sizing:border-box}body{margin:0;font-family:"Poppins","Segoe UI",Tahoma,Geneva,Verdana,sans-serif;background:#f3f4f6}.overlay{min-height:100vh;background:var(--bg);display:grid;place-items:center;padding:24px}.modal{width:min(980px,100%);background:var(--panel);border-radius:20px;box-shadow:0 20px 55px rgba(15,23,42,.25);padding:26px}h1{margin:0 0 6px;font-size:2.1rem}.muted{margin:0;color:var(--muted)}.panel{margin-top:18px;border:1px solid #e8ebf2;border-radius:16px;padding:16px}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.field{display:block;font-size:.9rem;color:#1f2937}input,select{width:100%;border:1px solid #d7dce7;border-radius:10px;padding:11px 12px;font:inherit}.full{grid-column:1/-1}.phone-group{display:grid;grid-template-columns:130px 1fr;gap:8px}.actions{margin-top:14px;display:flex;justify-content:space-between;gap:8px;flex-wrap:wrap}.btn{border:1px solid #d1d5db;border-radius:10px;padding:10px 14px;background:#fff;color:#374151;text-decoration:none;font-size:.92rem;display:inline-flex;align-items:center;gap:6px;cursor:pointer}.btn.primary{background:var(--green);border-color:var(--green);color:#fff;font-weight:600}.field input,.field select,.field .phone-group{margin-top:6px}.req{color:#dc2626}.error{margin-top:14px;padding:12px 14px;border:1px solid #fecaca;background:#fef2f2;color:#991b1b;border-radius:12px}@media (max-width:760px){.grid{grid-template-columns:1fr}.phone-group{grid-template-columns:1fr}}</style></head>
<body>
<?php
require_once __DIR__ . '/view_bootstrap.php'; $esc = static fn ($value) => htmlspecialchars((string) $value, ENT_QUOTES, 'UTF-8'); $backUrl = function_exists('route') ? route('surveillance.company') : '#'; ?>
<div class="overlay"><form class="modal" method="post" action="<?php echo $esc(route('surveillance.company.store')); ?>" id="newCompanyForm" novalidate><input type="hidden" name="_token" value="<?php echo $esc(csrf_token()); ?>"><h1>New Company</h1><p class="muted">All fields are required.</p><?php if(isset($errors) && $errors->any()): ?><div class="error"><?php echo $esc($errors->first()); ?></div><?php endif; ?><div class="panel"><div class="grid"><label class="field">Company Name <span class="req">*</span><input name="company_name" type="text" value="<?php echo $esc(old('company_name')); ?>" placeholder="Enter company name" required></label><label class="field">MYKPP Registration No <span class="req">*</span><input name="mykpp_registration_no" type="text" value="<?php echo $esc(old('mykpp_registration_no')); ?>" placeholder="Enter registration no" required></label><label class="field full">Company Address <span class="req">*</span><input name="company_address" type="text" value="<?php echo $esc(old('company_address')); ?>" placeholder="Enter address" required></label><label class="field">Company Postcode <span class="req">*</span><input name="company_postcode" type="text" value="<?php echo $esc(old('company_postcode')); ?>" placeholder="Enter postcode" pattern="^[0-9]{4,10}$" required></label><label class="field">Company District <span class="req">*</span><input name="company_district" type="text" value="<?php echo $esc(old('company_district')); ?>" placeholder="Enter district" required></label><label class="field">Company State <span class="req">*</span><input name="company_state" type="text" value="<?php echo $esc(old('company_state')); ?>" placeholder="Enter state" required></label><label class="field">Company Telephone <span class="req">*</span><div class="phone-group"><select name="company_phone_code" required><option value="">Code</option><?php foreach (['+60','+65','+62','+66','+1','+44'] as $code): ?><option value="<?php echo $esc($code); ?>"<?php echo old('company_phone_code', '+60') === $code ? ' selected' : ''; ?>><?php echo $esc($code); ?></option><?php endforeach; ?></select><input name="company_telephone" type="tel" value="<?php echo $esc(old('company_telephone')); ?>" inputmode="numeric" placeholder="Phone number" pattern="^[0-9]{7,12}$" required></div></label><label class="field">Company Email <span class="req">*</span><input name="company_email" type="email" value="<?php echo $esc(old('company_email')); ?>" placeholder="Enter email" required></label><label class="field">Company Fax <span class="req">*</span><input name="company_fax" type="text" value="<?php echo $esc(old('company_fax')); ?>" placeholder="Enter fax" required></label><label class="field">Total Workers <span class="req">*</span><input name="total_workers" type="number" min="0" value="<?php echo $esc(old('total_workers', 0)); ?>" placeholder="Enter total workers" required></label></div></div><div class="actions"><a class="btn" href="<?php echo $esc($backUrl); ?>">Cancel</a><button class="btn primary" type="submit">Submit Company</button></div></form></div><script>(function(){const form=document.getElementById('newCompanyForm');form.addEventListener('submit',function(event){if(!form.checkValidity()){event.preventDefault();form.reportValidity();}});})();</script>
</body></html>


